// Script Continued Below
// dtechMouseOver
// Use this service to hover over items in gojs or other angularjs capabilities
// For example, given the following string, get the first 5 readable characters

function dtechOrganizationalUser($document, $location, $timeout, $http) {
	var self = this;

	var getBaseURL = _getBaseURL;
	var error = _error;
	var getOrgAPIURL = _getOrgAPIURL;
	var getPhotoInfo = _getPhotoInfo;
	var getUserProfile = _getUserProfile;
	var success = _success;
	return {
		getUserProfile: getUserProfile,
		getPhotoInfo: getPhotoInfo
	};

	function _getBaseURL(){
		var protocol = $location.protocol();
		var host = $location.host();
		var baseURL = protocol + "://" + host;
		return baseURL;		
	}

	function _error(err){
// TODO - handle Error better
		return err.statusText;
	}

	function _getOrgAPIURL(){
		var baseURL = getBaseURL();
		var org_api_url = baseURL +
				"/api/x_153465_discovert/organizational_user/";
		return org_api_url;		
	}

	function _getPhotoInfo(userId){
		var org_api_url = getOrgAPIURL();
		var endPoint = org_api_url + userId + '/getUserPhotoInfo';
		var requestBody = ""; 
		return $http.get(endPoint).then(success, error);
	}

	function _getUserProfile(userId){
		var org_api_url = getOrgAPIURL();
		var endPoint = org_api_url + userId + '/getUserProfile';
		var requestBody = ""; 
		return $http.get(endPoint).then(success, error);
	}

	function _success(response){
		return response.data.result;
	}

}
